const data = $input.first().json;
const repoPath = data.repo || 'acme/backend-api';
const pipeline = data.pipeline || data.name || 'unknown';
const branch = data.branch || 'main';
const summary = data.error_summary || 'See pipeline logs for details.';
const consecutiveFails = data.consecutive_failures || 3;

return [{
  json: {
    owner: repoPath.split('/')[0],
    repo: repoPath.split('/')[1] || repoPath,
    title: `[Aeon] ${pipeline} has failed ${consecutiveFails} times on ${branch}`,
    body: `## Automated Failure Report

Aeon detected **${consecutiveFails} consecutive failures** on the \`${pipeline}\` pipeline.

### Details
| Field | Value |
|-------|-------|
| Pipeline | \`${pipeline}\` |
| Branch | \`${branch}\` |
| Consecutive Failures | ${consecutiveFails} |
| Last Commit | \`${data.commit_sha || 'unknown'}\` |
| Build URL | ${data.url ? `[View Build](${data.url})` : 'N/A'} |

### Root Cause Analysis
> ${summary}

### Suggested Actions
- [ ] Check the [Aeon AI Assistant](http://localhost:3000/ai) for detailed root cause analysis
- [ ] Review recent commits on \`${branch}\`
- [ ] Check for environment or dependency changes
- [ ] If flaky test, mark with \`flaky\` label and skip temporarily

---
*Auto-filed by [Aeon](http://localhost:3000) · ${new Date().toISOString()}*`,
    labels: ['bug', 'ci-failure', 'aeon-detected']
  }
}];
